+  projector.projectLaser(scan, cloud_out, -1.0, false);
+  EXPECT_EQ(cloud_out.channels.size(), (unsigned int)2);
+  projector.projectLaser(scan, cloud_out, -1.0, false, laser_geometry::MASK_INTENSITY | laser_geometry::MASK_INDEX);
+  EXPECT_EQ(cloud_out.channels.size(), (unsigned int)2);
