+  {
+    int d = 0;
+    float *pstep = (float*)&cloud_out.data[i * cloud_out.point_step];
+
+    // Copy XYZ
+    pstep[d++] = output (i, 0);
+    pstep[d++] = output (i, 1);
+    pstep[d++] = 0;
+
+    // Copy intensity
+    if (store_intensity)
+      pstep[d++] = scan_in.intensities[i];
+
+    // Copy distance
+    pstep[d++] = scan_in.ranges[i];
+
+    // Copy timestamp
+    pstep[d++] = i * scan_in.time_increment;
+
+    // Copy viewpoint (0, 0, 0)
+    pstep[d++] = 0;
+    pstep[d++] = 0;
+    pstep[d++] = 0;
