+        //   Since we still might need the x value we store it in the distance field
+        pstep[0] = bad_point;           // X -> NAN to mark a bad point
+        pstep[1] = co_sine_map (i, 1);  // Y
+        pstep[2] = 0;                   // Z
+
+        if (store_intensity)
+        {
+          pstep[3] = bad_point;           // Intensity -> NAN to mark a bad point
